import React, { FC, RefObject } from "react"
import { FlatList, RefreshControl } from "react-native"
import { CardVehicleTags, Text, Image, Box, Skeleton, PropsIconsNameCore } from "@semparar/design-system-app"
import BasicScreen from "../../atomic/templates/BasicScreen"
import ApiError from '../../atomic/organisms/ApiError';
import FiltersBottomSheet from '../../atomic/organisms/FiltersBottomSheet';
import { MyOrdersItemPropsView, STATUS_COLORS } from "./models";
import { PropsModalizeRef } from "@semparar/design-system-app/src/@types/modelize";

const MyOrdersRewardProgramView: FC<MyOrdersItemPropsView> = ({
    handleGoBack,
    myOrders,
    emptyImage,
    formatDate,
    isLoading,
    isError,
    modalizeRefFilters,
    handleOpenFilters,
    handleDetailsOrders,
    handleRefresh,
    filterGroups,
    isRefreshing,
    skeletonCount,
    screenWidth,
    handleApplyFilters,
    initialFilters,
    activeFiltersCount
}) => {

    return (
        <BasicScreen
            title="Meus pedidos"
            errorButtonOnPress={() => { }}
            hasScroll={false}
            leftIconOnPress={handleGoBack}
            rightIcon="icon-filter-settings"
            rightIconOnPress={handleOpenFilters}
            hasRightIcon={((!!myOrders.length) || (Number(activeFiltersCount) > 0))}
            scrollViewProps={{
                refreshControl: (
                    <RefreshControl
                        onRefresh={handleRefresh}
                        refreshing={isRefreshing}
                        tintColor={"BRAND_BASE_01"}
                    />
                ),
            }}
            version="2.0"
            showNotification={(Number(activeFiltersCount) > 0)}
            notificationNumber={activeFiltersCount}

        >

            {isLoading && (
                <Box width={screenWidth} mt="nano">
                    <FlatList
                        testID="loading-list-cashback"
                        data={Array.from({ length: skeletonCount })}
                        keyExtractor={(_, index) => index.toString()}
                        scrollEnabled={false}
                        renderItem={() => (
                            <Skeleton
                                testID="loading-orders-cashback"
                                width={screenWidth - 64}
                                height={150}
                                type="light"
                                mt="nano"
                                mb="nano"
                                mr="medium"
                                ml="medium"
                                borderRadiusTopLeft="half"
                            />
                        )}

                    />
                </Box>
            )}


            {isError && (
                <ApiError
                    testID="orders-cashback-error"
                    title="Algo deu errado!"
                    subTitle="Por favor, tente mais tarde"
                    isLoading={isLoading}
                    hasBackToHome={false}
                    onPress={handleGoBack}
                />
            )}


            {!isLoading && !isError && (<FlatList
                key={`${isLoading}-${myOrders.length}`}
                data={myOrders}
                renderItem={({ item }) => (
                    <Box ml="middle" mr="middle" mt="smaller">
                        <CardVehicleTags
                            vehicleName={item.description}
                            icon={item.icon as PropsIconsNameCore}
                            title="Valor em pontos"
                            titleDescription={String(Math.abs(item.amount))}
                            date="Data do resgate"
                            dateNumber={formatDate(item.date)}
                            statusTitle="Status do pedido"
                            status={item.status}
                            ghostButtonText="Exibir detalhes"
                            onGhostButtonPress={handleDetailsOrders}
                            type="extended"
                            typeTag={STATUS_COLORS[item.status] ?? 'alert'}
                            version="2.0"
                        />
                    </Box>
                )}
                ListEmptyComponent={() => (
                    <Box align="center" pd="innerLarger" justify="center" mt="larger">
                        <Image
                            resizeMode="contain"
                            source={{ uri: emptyImage }}
                            width={80}
                            height={80}
                        />
                        {activeFiltersCount ? (
                            <Text type="paragraphXXXL" mt="nano">
                                Não há resultados para sua busca
                            </Text>
                        ) : (
                            <>
                                <Text type="paragraphXXXL" mt="nano">
                                    Nenhum pedido feito
                                </Text>

                                <Text type="paragraphLG" align="center" mt="nano">
                                    Quando você usar seus pontos em pedidos, eles aparecerão aqui.
                                </Text>
                            </>
                        )}
                    </Box>
                )}
            />)}
            {filterGroups.length > 0 && (
                <FiltersBottomSheet
                    modalizeRef={modalizeRefFilters as RefObject<PropsModalizeRef>}
                    filterGroups={filterGroups}
                    onApplyFilters={handleApplyFilters}
                    initialFilters={initialFilters}
                />
            )}

        </BasicScreen>
    )
}


export default MyOrdersRewardProgramView;

import React, { FC } from 'react';
import { InvoiceCashbackViewProps } from './models';
import { Box, Text, ListTextIcon } from '@semparar/design-system-app';
import BasicScreen from '../../atomic/templates/BasicScreen';
import { Button } from '@semparar/design-system-app';
import { Skeleton } from '../../components/TransactionsListFactory/styles';

const InvoiceCashbackView: FC<InvoiceCashbackViewProps> = ({
  items,
  hasError,
  hasLoading,
  handleGoBack,
  handleContinue,
  handleRetry,
  cashbackInvoiceList,
  isLoadingParameterization,
  width,
}) => {
  return (
    <BasicScreen
      hasScroll
      hasHeader
      bgColor="BRAND_COMPLEMENT_03"
      leftIconOnPress={handleGoBack}
      title="Cashback na fatura"
      hasRightIcon={false}
      errorButtonOnPress={handleRetry}
      isLoading={hasLoading}
      hasError={hasError}
    >
      <Box ml="smaller" mr="smaller">
        <Text
          color="INTENSE_COLOR_05"
          testID="invoice-cashback-main-title"
          type="headingMDL"
          mt="smaller"
        >
          Use pontos para pagar menos na fatura
        </Text>
      </Box>
      {isLoadingParameterization &&
        cashbackInvoiceList?.map?.((item) => (
          <Box pd="innerLarge" key={item.text}>
            <Skeleton width={width - 40} height={60} />
          </Box>
        ))}
      {!isLoadingParameterization && (
        <>
          <Box ml="nano" mr="nano" flex={1} justify="flex-start">
            <ListTextIcon items={items} ml="nano" mr="xs" mt="xxs" type="list" />
          </Box>

          <Box ml="smaller" mr="smaller">
            <Button
              text="Continuar"
              mt="large"
              mb="small"
              onPress={handleContinue}
              testID="invoice-cashback-button"
            />
          </Box>
        </>
      )}
    </BasicScreen>
  );
};

export default InvoiceCashbackView;

