import React, { FC, useEffect, useState, useLayoutEffect, useMemo, useRef } from 'react';
import { NavigationProp, useNavigation, useIsFocused } from '@react-navigation/native';
import { Dimensions } from 'react-native';
import { useFocusEffect } from '@react-navigation/native';

import { useScreenViewTracking } from '../../hooks/tracking';

import theme from '../../styles/theme';
import { CashbackInvoiceItem, InvoiceCashbackProps } from './models';
import { PropsRootStack } from '../../routes/Models';
import InvoiceCashbackSummaryView from './view';
import { useInvoiceCashbackPermission } from '../../services/hooks';
import { useRootStore } from '~/store';
import { postRescue, clearRescue } from '../../services/services';
import { RescueStatus, RescuePayload } from '../../services/models';

const InvoiceCashbackSummary: FC<InvoiceCashbackProps> = ({ route }) => {
  useScreenViewTracking({ route, title: 'Cashback na fatura' });
  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
  const isFocused = useIsFocused();
  const { height } = Dimensions.get('window');
  const { hasRedeemed, markAsRedeemed } = useInvoiceCashbackPermission();
  const alreadyMarkedRef = useRef(false);
  const [hasAttemptedRescue, setHasAttemptedRescue] = useState(false);

  const { conversionFactor } = useRootStore((state) => state.pointsProducts);
  const { status: rescueStatus, response: rescueResponse } = useRootStore((state) => state.rescue);

  const isRescueLoading = rescueStatus === RescueStatus.LOADING;
  const isRescueFailed = rescueStatus === RescueStatus.ERROR;
  const isRescueConcluded = rescueStatus === RescueStatus.SUCCESS && !!rescueResponse;

  useLayoutEffect(() => {
    if (isFocused) {
      setHasAttemptedRescue(false);
      clearRescue();
    }
  }, [isFocused]);

  useFocusEffect(
    React.useCallback(() => {
      setHasAttemptedRescue(false);
      clearRescue();
      return undefined;
    }, [])
  );

  const handleGoBack = () => {
    setHasAttemptedRescue(false);
    clearRescue();
    navigation.goBack();
  };

  const invoiceList = (pts: number): CashbackInvoiceItem[] => {
    const whiteShape = theme.colors.LIGHT_BASE_01;
    const fintechColor = theme.colors.SECONDARY_COLOR_02;
    const finalPrice = pts * conversionFactor;
    const formattedPrice = new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL',
    }).format(finalPrice);

    return [
      {
        type: 'default',
        icon: 'icon-switch-vertical',
        iconColor: fintechColor,
        iconColorShape: whiteShape,
        description: `Cada ${pts.toLocaleString('pt-br')} pontos valem ${formattedPrice} no cashback`,
      },
      {
        type: 'default',
        icon: 'icon-calendar',
        iconColor: fintechColor,
        iconColorShape: whiteShape,
        description: 'Você define quanto cashback quer aplicar na sua fatura aberta',
      },
      {
        type: 'default',
        icon: 'icon-payment-invoice',
        iconColor: fintechColor,
        iconColorShape: whiteShape,
        description: 'Se o valor for maior que o da fatura, a diferença será aplicada nas próximas',
      },
      {
        type: 'default',
        icon: 'icon-clock',
        iconColor: fintechColor,
        iconColorShape: whiteShape,
        description: 'O cashback acontece em até 72h',
      },
    ];
  };

  const pointsSelected = route?.params?.pointsSelected ?? 0;
  const reaisSelected = route?.params?.reaisSelected ?? 0;
  const productCode = route?.params?.productCode;
  const campaingId = route?.params?.campaingId;

  const onConfirmRescue = async () => {
    setHasAttemptedRescue(true);
    const payload: RescuePayload = {
      value: pointsSelected,
      campaignId: campaingId,
      productCode: productCode,
      description: 'Cashback resgatado',
    };
    await postRescue(payload);
  };

  const onExitResult = () => {
    setHasAttemptedRescue(false);
    clearRescue();
    navigation.navigate('RewardProgram');
  };

  const showResult = isFocused && hasAttemptedRescue && (isRescueConcluded || isRescueFailed);

  const items = invoiceList(pointsSelected).map((item) => ({
    icon: item.icon,
    iconColor: item.iconColor,
    description: item.description,
    iconColorShape: item.iconColorShape,
    type: item.type,
  }));

  const modalizeRef1 = useRef(null);

  const onOpenDefault = () => {
    modalizeRef1.current?.open();
  };

  useEffect(() => {
    if (showResult && isRescueConcluded && !alreadyMarkedRef.current && hasRedeemed !== true) {
      alreadyMarkedRef.current = true;
      markAsRedeemed().catch(() => {});
    }
  }, [showResult, isRescueConcluded, hasRedeemed, markAsRedeemed]);

  const nfPtBR = useMemo(() => new Intl.NumberFormat('pt-BR'), []);
  const getFormatPoints = (n: number) => nfPtBR.format(Math.max(0, Math.floor(n || 0)));
  const formatCurrencyBR = (n: number) =>
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' })
      .format(Number.isFinite(n) ? n : 0)
      .replace(/\s/g, '');

  const formattedSelectedPoints = useMemo(
    () => getFormatPoints(pointsSelected || 0),
    [pointsSelected]
  );

  const formattedSelectedReais = useMemo(
    () => formatCurrencyBR(reaisSelected || 0),
    [reaisSelected]
  );

  const effectiveShowResult =
    typeof showResult !== 'undefined' ? showResult : !!(isRescueConcluded || isRescueFailed);
  const screenTitle = effectiveShowResult ? 'Conclusão' : 'Cashback na fatura';

  return (
    <InvoiceCashbackSummaryView
      handleGoBack={handleGoBack}
      onConfirmRescue={onConfirmRescue}
      onExitResult={onExitResult}
      isRescueLoading={isRescueLoading}
      isRescueConcluded={isRescueConcluded}
      isRescueFailed={isRescueFailed}
      items={items}
      effectiveShowResult={showResult}
      onOpenDefault={onOpenDefault}
      modalizeRef1={modalizeRef1}
      formattedSelectedPoints={formattedSelectedPoints}
      formattedSelectedReais={formattedSelectedReais}
      screenTitle={screenTitle}
      height={height}
    />
  );
};

export default InvoiceCashbackSummary;

# Frontend Style Guide — Sem Parar (Zustand-only + Hook Component Pattern)

Welcome to the **Sem Parar Frontend Style Guide**.  
This version consolidates: **Zustand as the only state manager**, **Hook Component pattern** for Screens and Atomic components, **services architecture (SOLID)**, and an **cache pattern**.

> Sit down, have a cup of coffee and read this calmly. ☕

---

## :pushpin: Table of Contents
- [Introduction](#introduction)
- [Components & Screens — Hook Component Pattern](#components--screens--hook-component-pattern)
- [Atomic Components — Hook Component Pattern](#atomic-components--hook-component-pattern)
- [Project Organization](#project-organization)
- [Services Architecture](#services-architecture)
- [State Management (Zustand-only)](#state-management-zustand-only)
- [Routes Naming](#routes-naming)
- [Folder Naming Rules](#folder-naming-rules)
- [Code Standards](#code-standards)
- [Styles Patterns](#styles-patterns)
- [Cache Pattern](#cache-pattern)
- [Checklist](#checklist)

---

## Introduction

The goal of this guide is to ensure **consistency, testability and scalability** across our frontend projects.

Key decisions:
- **Zustand** is the **exclusive** global/shared state manager.
- UI follows the **Hook Component** pattern (logic hook + dumb view).
- Domain logic lives in **`/services`** with **SOLID** layering.
- Cache is **typed and reusable**.

---

## Components & Screens — Hook Component Pattern

Each screen is split into a logic hook and a render-only component.

```
screens/Home/
├── index.ts        # logic: export useHomeScreen()
├── view.tsx        # render: export default HomeScreen
└── Models/
    └── index.d.ts    # types (Props, State, Handlers, Return)
```

**Models/index.d.ts**
```ts
export interface HomeParams {
  welcome?: string;
}
export interface HomeState {
  greeting: string;
  isLoading: boolean;
}
export interface HomeHandlers {
  onPressCTA: () => void;
}
export type UseHomeReturn = HomeState & HomeHandlers;
```

**index.ts (logic hook)**
```ts
import { useCallback, useMemo, useState, useEffect } from "react";
import type { HomeParams, UseHomeReturn } from "./Models";
import { useUserStore } from "@/services/user/store"; // Zustand slice example

export function useHomeScreen(params?: HomeParams): UseHomeReturn {
  const name = useUserStore((s) => s.name);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const t = setTimeout(() => setIsLoading(false), 300);
    return () => clearTimeout(t);
  }, []);

  const greeting = useMemo(
    () => params?.welcome ?? `Hello, ${name || "guest"}!`,
    [params?.welcome, name]
  );

  const onPressCTA = useCallback(() => {
    // Call services, analytics, navigation, etc.
  }, []);

  return { greeting, isLoading, onPressCTA };
}
```

**view.tsx (render)**
```tsx
import React from "react";
import { View } from "react-native";
import { Text, Button } from "@semparar/design-system-app";
import { useHomeScreen } from "./index";
import type { HomeParams } from "./Models";

type Props = HomeParams;

export default function HomeScreen(props: Props) {
  const { greeting, isLoading, onPressCTA } = useHomeScreen(props);

  if (isLoading) {
    return (
      <View>
        <Text>Loading...</Text>
      </View>
    );
  }

  return (
    <View>
      <Text>{greeting}</Text>
      <Button onPress={onPressCTA} text="Continue" />
    </View>
  );
}
```

---

## Atomic Components — Hook Component Pattern

```
atomic/atoms/Button/
├── index.ts        # logic: export useButton()
├── view.tsx        # render: export default Button
└── Models/
    └── index.d.ts
```

**Models/index.d.ts**
```ts
export interface ButtonProps {
  text: string;
  disabled?: boolean;
  onPress?: () => void;
}
export interface ButtonState {
  pressed: boolean;
}
export interface ButtonHandlers {
  handlePress: () => void;
}
export type UseButtonReturn = ButtonState & ButtonHandlers;
```

**index.ts (logic hook)**
```ts
import { useCallback, useState } from "react";
import type { ButtonProps, UseButtonReturn } from "./Models";

export function useButton(props: ButtonProps): UseButtonReturn {
  const [pressed, setPressed] = useState(false);

  const handlePress = useCallback(() => {
    setPressed(true);
    props.onPress?.();
    setTimeout(() => setPressed(false), 150);
  }, [props.onPress]);

  return { pressed, handlePress };
}
```

**view.tsx (render)**
```tsx
import React from "react";
import { Pressable, View } from "react-native";
import { Text } from "@semparar/design-system-app";
import { useButton } from "./index";
import type { ButtonProps } from "./Models";

export default function Button(props: ButtonProps) {
  const { pressed, handlePress } = useButton(props);

  return (
    <Pressable disabled={props.disabled} onPress={handlePress}>
      <View>
        <Text>{props.text}{pressed ? " •" : ""}</Text>
      </View>
    </Pressable>
  );
}
```

